class Solution:
    def strangePrinter(self, s: str) -> int:
        n = len(s)
        dp = [1] * (n + 1)
        for i in range(1, n):
            for j in range(i):
                if s[i] == s[j]:
                    dp[i + 1] = min(dp[i + 1], dp[j + 1] + 1)
                else:
                    dp[i + 1] = min(dp[i + 1], dp[j + 1] + 1)
        return dp[n]
```
